UPDATE order_claim
SET claim_status = #{claim_status}
WHERE claim_code = #{claim_code}

UPDATE order_claim
SET claim_type = #{claim_type}
WHERE claim_code = #{claim_code}

mapper.select:
SELECT * FROM ( SELECT claim_data.*, ROWNUM AS "ROW_NUMBER" FROM ( SELECT oc.CLAIM_CODE AS "claim_code", oc.C_CODE AS "c_code", oc.ID AS "id", u.NAME AS "user_name", u.TEL AS "user_tel", u.EMAIL AS "user_email",
oc.F_CODE AS "f_code", f.F_NAME AS "f_name", f.C_ID AS "c_id", f.C_KIND AS "c_kind", f.C_NAME AS "c_name",
c.F_COUNT AS "f_count", c.F_PRICE AS "f_price", c.PAY_TOTAL AS "pay_total", c.CART_PAYDATE AS "cart_paydate",
oc.CLAIM_TYPE AS "claim_type", CASE oc.CLAIM_TYPE WHEN 1 THEN '교환' WHEN 2 THEN '반품' ELSE '알 수 없음' END AS "claim_type_name",
oc.CLAIM_STATUS AS "claim_status", CASE oc.CLAIM_STATUS WHEN 0 THEN '신청완료' WHEN 1 THEN '접수' WHEN 2 THEN '처리중' WHEN 3 THEN '처리완료' WHEN -1 THEN '거절' ELSE '알 수 없음' END AS "claim_status_name",
oc.CLAIM_REASON AS "claim_reason", oc.CLAIM_CREATEDDATE AS "claim_createddate",
COUNT(*) OVER () AS "total_count" FROM ORDER_CLAIM oc JOIN FURNITURE f ON oc.F_CODE = f.F_CODE LEFT JOIN CART c ON oc.C_CODE = c.C_CODE LEFT JOIN USERS u ON oc.ID = u.ID
f.C_ID = #{c_id} AND f.C_KIND = #{c_kind}
AND f.C_NAME = #{c_name}
AND oc.CLAIM_TYPE = #{claimType}
AND oc.CLAIM_STATUS = #{claimStatus}
AND oc.CLAIM_CREATEDDATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND oc.CLAIM_CREATEDDATE < TO_DATE(#{endDate}, 'YYYY-MM-DD') + 1
AND ( oc.CLAIM_CODE LIKE '%' || #{keyword} || '%' OR oc.C_CODE LIKE '%' || #{keyword} || '%' OR oc.ID LIKE '%' || #{keyword} || '%' OR f.F_NAME LIKE '%' || #{keyword} || '%' OR oc.CLAIM_REASON LIKE '%' || #{keyword} || '%' )
ORDER BY oc.CLAIM_CREATEDDATE DESC, oc.CLAIM_CODE DESC ) claim_data WHERE ROWNUM <= #{endRow} ) WHERE "ROW_NUMBER" > #{offset}
